INSERT INTO `projects` VALUES (2,'R190388','CHEPPALI KALYANI','D','G.Swapna','Project duplicate checker','A project duplicate checker is a tool that helps identify and prevent duplicate project submissions by students. It compares project titles, descriptions, and other attributes to flag any potential duplicates within a database, ensuring originality and proper project allocation','Accepted',15),(3,'R190036','M HARISH NAICK','D','P.UdaySree','Lung cancer Detection','An innovative system for early and accurate detection of lung cancer using advanced machine learning algorithms.','Accepted',7),(4,'R190349','S ARBIN TAJ','D','P.UdaySree','Lung cancer Detection','An innovative system for early and accurate detection of lung cancer using advanced machine learning algorithms','Accepted',7),(5,'R190259','H.THEJASWINI','D','M.Muni Babu','CROP RECOMMENDATION','to recommend crop for farmers','Accepted',8),(6,'R190273','Swapna','D','G.Swapna','Digital Farming','recommends fertilizers','Accepted',15),(7,'R190388','CHEPPALI KALYANI','D','G.Swapna','DUPLICATE PROJECT CHECKER','to konow about existing projects and then we create new proects which are not done by our college students','Accepted',15);
